sql:
SELECT COUNT(*) AS total_trade_agreements
FROM trade_agreements
WHERE end_date BETWEEN '2024-01-01' AND '2024-12-31';

SELECT mfn_id
FROM mfn_tariffs
WHERE rate < 0.1;

SELECT reporter_name
FROM reporters
WHERE region = 'Region Y';

SELECT COUNT(DISTINCT tl_id) AS total_tariff_lines_with_MFN
FROM mfn_tariffs
WHERE implementation_date IS NOT NULL;

SELECT SUM(data_size)
FROM trade_data_exports
WHERE data_format = 'JSON';

SELECT reporter_name, region, contact_email, contact_phone, address 
FROM reporters 
WHERE reporter_id = 0;

SELECT category_name
FROM trade_categories
WHERE category_id = 0;

SELECT data_format, AVG(data_size) AS average_import_size
FROM trade_data_imports
GROUP BY data_format;

SELECT export_id, report_id 
FROM trade_data_exports 
WHERE data_format = 'CSV';

SELECT DISTINCT tc.category_name
FROM tariff_lines tl
JOIN trade_categories tc ON tl.category_id = tc.category_id;

SELECT DISTINCT c.country_name
FROM mfn_tariffs mt
INNER JOIN countries c ON mt.country_id = c.country_id;

SELECT reporters.reporter_name, tariff_lines.description
FROM reporters
JOIN tariff_lines ON reporters.reporter_id = tariff_lines.tl_id;

external_knowledge:
- Ways to reach out to entities or countries can be interpreted as contact information like emails and phone numbers; 
- Identifiers for the exports refer to unique identifiers used to track export events;
- Names and regions provide context about the reporters, typically referring to countries or entities that submit reports.

sql:
SELECT DISTINCT c.country_name
FROM countries c
JOIN trade_data_imports tdi ON c.country_id = tdi.report_id;

SELECT DISTINCT r.reporter_name, r.contact_email
FROM reporters r
JOIN mfn_tariffs m ON r.reporter_id = m.country_id;

SELECT COUNT(DISTINCT user_id) AS NumberOfExplorers
FROM access_logs
WHERE report_id IN (SELECT tl_id FROM tariff_lines);
